function email_id_allocation_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('email_id_allocation_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'name_of_person' => Request::val('name_of_person', ''),
		'allocated_email_id' => Request::val('allocated_email_id', ''),
		'alternative_email_id' => Request::val('alternative_email_id', ''),
		'date_of_allocation' => Request::dateComponents('date_of_allocation', ''),
		'status' => Request::val('status', ''),
		'reporting_manager' => Request::lookup('reporting_manager', ''),
		'remarks' => br2nl(Request::val('remarks', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('email_id_allocation_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		email_id_allocation_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function email_id_allocation_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function email_id_allocation_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('email_id_allocation_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: email_id_allocation_table_before_delete
	if(function_exists('email_id_allocation_table_before_delete')) {
		$args = [];
		if(!email_id_allocation_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `email_id_allocation_table` WHERE `email_id_allocation_id`='{$selected_id}'", $eo);

	// hook: email_id_allocation_table_after_delete
	if(function_exists('email_id_allocation_table_after_delete')) {
		$args = [];
		email_id_allocation_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='email_id_allocation_table' AND `pkValue`='{$selected_id}'", $eo);
}

function email_id_allocation_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('email_id_allocation_table', $selected_id, 'edit')) return false;

	$data = [
		'name_of_person' => Request::val('name_of_person', ''),
		'allocated_email_id' => Request::val('allocated_email_id', ''),
		'alternative_email_id' => Request::val('alternative_email_id', ''),
		'date_of_allocation' => Request::dateComponents('date_of_allocation', ''),
		'status' => Request::val('status', ''),
		'reporting_manager' => Request::lookup('reporting_manager', ''),
		'remarks' => br2nl(Request::val('remarks', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('email_id_allocation_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: email_id_allocation_table_before_update
	if(function_exists('email_id_allocation_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!email_id_allocation_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'email_id_allocation_table',
		backtick_keys_once($set),
		['`email_id_allocation_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="email_id_allocation_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('email_id_allocation_table', $data['selectedID'], calculated_fields()['email_id_allocation_table']);

	// hook: email_id_allocation_table_after_update
	if(function_exists('email_id_allocation_table_after_update')) {
		if($row = getRecord('email_id_allocation_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['email_id_allocation_id'];
		$args = ['old_data' => $old_data];
		if(!email_id_allocation_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('email_id_allocation_table', $selected_id);
}

